function validate(args, output) {
    const nums = args[0];
    if (typeof output !== 'string') return false;
    const n = nums.length;
    if (output.length !== n) return false;
    for (const c of output) {
        if (c !== '0' && c !== '1') return false;
    }
    return !nums.includes(output);
}

